 Begin SpecMap 	# Conversion between spectral coordinate systems
    Nin = 1 	# Number of input coordinates
 IsA Mapping 	# Mapping between coordinate systems
    Nspec = 30 	# Number of conversion steps
    Spec1 = "FRTOVL" 	# Convert frequency to rel. velocity
    Spec1a = 2000 	# Rest frequency (Hz)
    Spec2 = "VLTOFR" 	# Convert rel. velocity to frequency
    Spec2a = 2000 	# Rest frequency (Hz)
    Spec3 = "ENTOFR" 	# Convert energy to frequency
    Spec4 = "FRTOEN" 	# Convert frequency to energy
    Spec5 = "WNTOFR" 	# Convert wave number to frequency
    Spec6 = "FRTOWN" 	# Convert frequency to wave number
    Spec7 = "WVTOFR" 	# Convert wavelength (vacuum) to frequency
    Spec8 = "FRTOWV" 	# Convert frequency to wavelength (vacuum)
    Spec9 = "AWTOFR" 	# Convert wavelength (air) to frequency
    Spec10 = "FRTOAW" 	# Convert frequency to wavelength (air)
    Spec11 = "VRTOVL" 	# Convert radio to rel. velocity
    Spec12 = "VLTOVR" 	# Convert relativistic to radio velocity
    Spec13 = "VOTOVL" 	# Convert optical to rel. velocity
    Spec14 = "VLTOVO" 	# Convert relativistic to optical velocity
    Spec15 = "ZOTOVL" 	# Convert redshift to rel. velocity
    Spec16 = "VLTOZO" 	# Convert rel. velocity to redshift
    Spec17 = "BTTOVL" 	# Convert beta factor to rel. velocity
    Spec18 = "VLTOBT" 	# Convert rel. velocity to beta factor
    Spec19 = "TPF2HL" 	# Convert from Topocentric to heliocentric frequency
    Spec19a = 2000 	# Longitude (positive eastwards, radians)
    Spec19b = 2000 	# Latitude (geodetic, radians)
    Spec19c = 2000 	# Altitude (geodetic, metres)
    Spec19d = 2000 	# UT1 epoch of observaton (Modified Julian Date)
    Spec19e = 2000 	# RA of source (FK5 J2000, radians)
    Spec19f = 2000 	# DEC of source (FK5 J2000, radians)
    Spec20 = "HLF2TP" 	# Convert from Heliocentric to topocentric frequency
    Spec20a = 2000 	# Longitude (positive eastwards, radians)
    Spec20b = 2000 	# Latitude (geodetic, radians)
    Spec20c = 2000 	# Altitude (geodetic, metres)
    Spec20d = 2000 	# UT1 epoch of observaton (Modified Julian Date)
    Spec20e = 2000 	# RA of source (FK5 J2000, radians)
    Spec20f = 2000 	# DEC of source (FK5 J2000, radians)
    Spec21 = "USF2HL" 	# Convert from user-defined to heliocentric frequency
    Spec21a = 2000 	# Velocity offset (m/s)
    Spec21b = 2000 	# RA of source (FK5 J2000, radians)
    Spec21c = 2000 	# DEC of source (FK5 J2000, radians)
    Spec22 = "HLF2US" 	# Convert from heliocentric to user-defined frequency
    Spec22a = 2000 	# Velocity offset (m/s)
    Spec22b = 2000 	# RA of source (FK5 J2000, radians)
    Spec22c = 2000 	# DEC of source (FK5 J2000, radians)
    Spec23 = "GEF2HL" 	# Convert from Geocentric to heliocentric frequency
    Spec23a = 2000 	# UT1 epoch of observaton (Modified Julian Date)
    Spec23b = 2000 	# RA of source (FK5 J2000, radians)
    Spec23c = 2000 	# DEC of source (FK5 J2000, radians)
    Spec24 = "HLF2GE" 	# Convert from Heliocentric to geocentric frequency
    Spec24a = 2000 	# UT1 epoch of observaton (Modified Julian Date)
    Spec24b = 2000 	# RA of source (FK5 J2000, radians)
    Spec24c = 2000 	# DEC of source (FK5 J2000, radians)
    Spec25 = "BYF2HL" 	# Convert from Barycentric to heliocentric frequency
    Spec25a = 2000 	# UT1 epoch of observaton (Modified Julian Date)
    Spec25b = 2000 	# RA of source (FK5 J2000, radians)
    Spec25c = 2000 	# DEC of source (FK5 J2000, radians)
    Spec26 = "HLF2BY" 	# Convert from Heliocentric to barycentric frequency
    Spec26a = 2000 	# UT1 epoch of observaton (Modified Julian Date)
    Spec26b = 2000 	# RA of source (FK5 J2000, radians)
    Spec26c = 2000 	# DEC of source (FK5 J2000, radians)
    Spec27 = "LKF2HL" 	# Convert from LSRK to heliocentric frequency
    Spec27a = 2000 	# RA of source (FK5 J2000, radians)
    Spec27b = 2000 	# DEC of source (FK5 J2000, radians)
    Spec28 = "HLF2LK" 	# Convert from Heliocentric to LSRK frequency
    Spec28a = 2000 	# RA of source (FK5 J2000, radians)
    Spec28b = 2000 	# DEC of source (FK5 J2000, radians)
    Spec29 = "LDF2HL" 	# Convert from LSRD to heliocentric frequency
    Spec29a = 2000 	# RA of source (FK5 J2000, radians)
    Spec29b = 2000 	# DEC of source (FK5 J2000, radians)
    Spec30 = "HLF2LD" 	# Convert from Heliocentric to LSRD frequency
    Spec30a = 2000 	# RA of source (FK5 J2000, radians)
    Spec30b = 2000 	# DEC of source (FK5 J2000, radians)
 End SpecMap
